insert into public.rituals (id, name, language, region, pronunciation, cluster, type, promptable, solo_or_social, time_of_day, season, duration_minutes, essence, meaning, how_to, when_context, feeling, cultural_note, lomas_path, caution, sort_order)
values
  ('niksen', 'Niksen', 'Dutch', 'Netherlands', 'NIK-sen', 'pause', 'doable_activity', true, 'solo', 'any', 'any', 3, 'The art of doing absolutely nothing, on purpose.', 'Idleness with no aim and no guilt — not resting up for the next task, just being idle and letting that be enough. Often phrased *lekker niksen*, "delicious nothing".', ARRAY['Sit or lie somewhere comfortable with nothing to achieve', 'Let your gaze drift out a window', 'When the urge to be useful arrives, notice it and let it pass.']::text[], 'Any unclaimed pocket of time. Usually alone.', 'A loosening in the chest. Rest without a reason.', 'Popularised internationally around 2019 as a Dutch antidote to busyness.', NULL, NULL, 0),
  ('dolce-far-niente', 'Dolce far niente', 'Italian', 'Italy', 'DOL-chay far nee-EN-tay', 'pause', 'doable_activity', true, 'either', 'midday', 'warm_months', 5, 'The sweetness of doing nothing, and savouring it.', 'Guilt-free idleness treated as one of life''s real pleasures rather than a lapse.', ARRAY['Step away from the to-do list entirely', 'Find sun, shade, a good chair or a slow drink', 'Let the minutes go uncounted.']::text[], 'A long lunch, a warm afternoon, a Sunday with no plans.', 'Time slows and stops feeling like something to spend.', 'Associated with Italy''s slower regional rhythms and Blue Zone longevity.', 'Feelings > Positive > Savouring', NULL, 1),
  ('fjaka', 'Fjaka', 'Croatian', 'Dalmatia, Croatia', 'FYAH-kah', 'pause', 'doable_activity', true, 'either', 'afternoon', 'summer', 5, 'A blissful, dreamy slowing-down — laziness, perfected.', 'A celebrated Dalmatian state of being so relaxed you barely move and feel no need to.', ARRAY['Wait for the heat of the day or a heavy, full feeling after a meal', 'Find shade and somewhere to recline', 'Surrender; resistance is the only thing that can ruin it.']::text[], 'Hot afternoons, especially in summer along the coast.', 'Total, unbothered ease. The world can wait.', 'A point of regional pride along the Adriatic coast.', NULL, NULL, 2),
  ('keyif', 'Keyif', 'Turkish', 'Türkiye', 'kay-EEF', 'pause', 'doable_activity', true, 'either', 'any', 'any', 4, 'Quiet, intentional idle pleasure, usually with tea and a view.', 'Carving out a small, savoured pause for no reason other than that it feels good.', ARRAY['Make tea or coffee, properly', 'Take it somewhere with a view — a balcony, a kerb, the sea', 'Drink it slowly and watch the world go by.']::text[], 'Stolen at any hour. Often shared, often silent.', 'A settled, unhurried contentment.', 'Frequently cited as a Turkish wellbeing word not captured by standard happiness measures.', NULL, NULL, 3),
  ('hygge', 'Hygge', 'Danish', 'Denmark', 'HOO-guh', 'pause', 'doable_activity', true, 'either', 'evening', 'cold_months', 4, 'Cosy contentment, built from small warm things.', 'Candlelight, wool socks, a hot drink and easy company — comfort assembled on purpose against the dark. Goes beyond physical comfort to emotional and existential warmth.', ARRAY['Lower the lights and light a candle', 'Make something warm to hold', 'Gather what comforts you — a blanket, a book, a person — and stay put.']::text[], 'Autumn and winter evenings especially. Alone or with a close few.', 'Safe, warm, quietly glad to be where you are.', 'A hallmark of Danish identity. Note this is the most commercialised term in the catalogue; keep it grounded in atmosphere, not products.', 'Feelings > Positive > Cosiness', 'Heavily commercialised abroad — present as a feeling, not a shopping list.', 4),
  ('koselig', 'Koselig', 'Norwegian', 'Norway', 'KOOSH-lee', 'pause', 'doable_activity', true, 'either', 'evening', 'cold_months', 4, 'Warm, convivial cosiness — the Norwegian cousin of hygge.', 'A sense of warmth and togetherness: bonfires, coffee and pastry with friends, candles against a winter storm.', ARRAY['Warm and soften the space — light, blankets, a fire if you have one', 'Bring in a hot drink and good company or a good book', 'Let it feel unhurried.']::text[], 'Dark and cold evenings, alone or with others.', 'Glowing, sheltered warmth.', 'Part of a Northern European family of "cosiness" words; consider grouping with hygge, mysa, gezelligheid and Gemütlichkeit as variants.', 'Feelings > Positive > Cosiness', NULL, 5),
  ('mysa', 'Mysa', 'Swedish', 'Sweden', 'MEE-sah', 'pause', 'doable_activity', true, 'either', 'evening', 'cold_months', 4, 'To snuggle down and feel cosy and content, usually at home.', 'The Swedish cosiness verb — to make yourself comfortable and enjoy a soft, warm moment.', ARRAY['Get comfortable somewhere soft', 'Add warmth — a blanket, a drink, low light', 'Let yourself settle and enjoy it.']::text[], 'Evenings at home, especially in colder months.', 'Soft, contented, at ease.', 'Closely related to *mysig* (the adjective).', 'Feelings > Positive > Cosiness', NULL, 6),
  ('gemutlichkeit', 'Gemütlichkeit', 'German', 'Germany', 'ge-MOOT-lish-kite', 'pause', 'state_of_mind', true, 'either', 'evening', 'cold_months', 4, 'Warmth, friendliness, belonging and peace of mind.', 'A cosy, convivial atmosphere combined with a feeling of social ease and being at home in a place.', ARRAY['Choose a warm, unpretentious setting', 'Slow the pace and lower the stakes', 'Let comfort and company do the rest.']::text[], 'Evenings, gatherings, snug rooms.', 'Relaxed belonging.', 'The German member of the cosiness family.', 'Feelings > Positive > Cosiness', NULL, 7),
  ('feierabend', 'Feierabend', 'German', 'Germany', 'FY-er-ah-bent', 'pause', 'doable_activity', true, 'either', 'evening', 'any', 0, 'The festive, unwound mood at the close of the working day.', 'Literally "celebration evening" — the moment work stops and rest, not more activity, begins. A real psychological boundary on the day.', ARRAY['Mark a clear end to work — close the laptop, change clothes, step outside', 'Do something that is the opposite of the day''s tasks', 'Protect it from being eaten by chores.']::text[], 'Evening, after work.', 'Earned release and the day handed back to you.', 'Lomas places it among words of revelry and end-of-day pleasure.', 'Feelings > Positive > Revelry', NULL, 8),
  ('meriggiare', 'Meriggiare', 'Italian', 'Italy', 'meh-reej-JAH-reh', 'pause', 'doable_activity', true, 'either', 'midday', 'summer', 5, 'To rest in the shade through the hottest part of the day.', 'A single verb for retreating from the midday heat into cool, still shade.', ARRAY['When the sun is high and fierce, stop', 'Find a tree, an awning or a shuttered room', 'Stay slow and quiet until the heat softens.']::text[], 'Midday, summer.', 'Cool relief and a guilt-free pause.', 'The instinct behind the siesta.', NULL, NULL, 9),
  ('kalsarikannit', 'Kalsarikännit', 'Finnish', 'Finland', 'KAL-sah-ree-kan-nit', 'pause', 'doable_activity', true, 'solo', 'evening', 'any', 0, 'Drinking at home, in your underwear, with no plan to go out.', '"Pants drunk" — unpretentious, solitary decompression with zero social performance.', ARRAY['Cancel any plan to go out', 'Get comfortable at home in whatever you like', 'Have a drink, or don''t, and do nothing in particular.']::text[], 'Evenings, alone or with someone very close.', 'Freedom from being seen, and total ease.', 'Has its own officially released Finnish emoji. Keep it light and optional given the alcohol element.', NULL, NULL, 10),
  ('wu-wei', 'Wú wéi', 'Chinese', 'China', 'woo-WAY', 'pause', 'state_of_mind', false, 'either', 'any', 'any', 0, 'Effortless action — doing without forcing.', 'Literally "do nothing", but meaning to act so naturally and in tune with the moment that effort disappears. A central Taoist idea.', ARRAY['Notice where you are straining or forcing', 'Loosen your grip on the outcome', 'Let the next right action arise rather than driving it.']::text[], 'A way of approaching tasks rather than a scheduled activity.', 'Flow, ease, and less friction.', 'Rooted in Taoism and alignment with the Tao. Best used as a reflective theme, not a timed prompt.', 'Character > Spirituality > Path', NULL, 11),
  ('boketto', 'Boketto', 'Japanese', 'Japan', 'boh-KET-toh', 'pause', 'perceptual_noticing', true, 'solo', 'any', 'any', 3, 'Gazing into the middle distance, thinking of nothing at all.', 'A word for letting your eyes rest on nothing in particular and your mind go pleasantly blank — vacant, unfocused, and entirely on purpose.', ARRAY['Let your eyes settle on the far distance — a window, a horizon, a wall', 'Stop directing your thoughts and let them idle', 'When you notice you have drifted, don''t pull yourself back; stay a little longer.']::text[], 'Any small gap — a train window, a kettle boiling, a free minute.', 'A soft, untethered emptiness; the mind off its leash.', 'A gently humorous Japanese word that treats vacant staring as something restorative rather than a lapse.', NULL, NULL, 12),
  ('querencia', 'Querencia', 'Spanish', 'Spain and Latin America', 'keh-REN-see-ah', 'pause', 'state_of_mind', true, 'solo', 'any', 'any', 4, 'Retreating to the place where you feel most yourself and strong.', 'From *querer*, "to desire" — the spot a person is drawn to for safety and renewal, where they feel grounded and most at home in themselves. Originally the part of the ring a bull returns to in order to gather its strength.', ARRAY['Picture the place where you feel steadiest — a chair, a room, a path, a view', 'Go there, or bring its feeling to mind', 'Let it return you to yourself before you step back out.']::text[], 'When the day has scattered you and you need to come home to yourself.', 'Gathered, rooted, quietly restored.', 'Drawn from Spanish, by way of bullfighting, into wider use as a word for one''s place of refuge and strength.', NULL, NULL, 13),
  ('sukoon', 'Sukoon', 'Arabic and Urdu', 'Middle East and South Asia', 'soo-KOON', 'pause', 'state_of_mind', true, 'either', 'any', 'any', 4, 'A deep, settled calm that arrives once the storm has passed.', 'A profound tranquillity and stillness of heart — not mere relaxation but a hard-won peace that settles over you after agitation, fear or noise.', ARRAY['Find somewhere quiet and let your breathing slow', 'Set down, for now, whatever you are gripping', 'Let the stillness arrive on its own rather than chasing it.']::text[], 'After a hard day, or any time the mind needs to settle.', 'A spacious, anchored calm.', 'A treasured word in Arabic and Urdu, with roots in the Quran, where it names the peace sent into the heart. Present it gently and with respect for that source.', NULL, 'Carries sacred, Quranic resonance — frame as quiet calm, not a generic relaxation hack.', 14),
  ('loyly', 'Löyly', 'Finnish', 'Finland', 'LOY-loo', 'pause', 'doable_activity', true, 'either', 'evening', 'any', 5, 'The wave of soft heat when water meets hot sauna stones.', 'The steam — and the almost spiritual surge of warmth — that rises when water is ladled onto the sauna stones. Finns treat the moment as sacred recovery, not to be disturbed.', ARRAY['In a sauna or any warm, steamy place, settle and slow down', 'Add water to the stones, or simply let the heat wrap around you', 'Breathe it in and let your shoulders drop; say nothing.']::text[], 'Evenings, the end of the week, or any time you need to be thawed out.', 'Loosened muscles, a cleared head, deep bodily calm.', 'Finnish sauna culture is on UNESCO''s list of intangible cultural heritage; löyly is its quiet heart.', NULL, NULL, 15),
  ('livsnjutning', 'Livsnjutning', 'Swedish', 'Sweden', 'LEEVS-nyoot-ning', 'pause', 'perceptual_noticing', true, 'either', 'any', 'any', 3, 'Consciously relishing one of life''s small everyday pleasures.', 'Literally "life-enjoyment" — the deliberate savouring of an ordinary good moment, choosing to taste life rather than merely get through it.', ARRAY['Notice one small pleasure available right now — warmth, a flavour, a sound', 'Give it your full attention for a moment', 'Let yourself enjoy it without hurrying to the next thing.']::text[], 'Any ordinary moment that is quietly good.', 'A small, conscious gladness.', 'A Swedish word for the art of appreciating life''s simple pleasures as they happen.', 'Feelings > Positive > Savouring', NULL, 16),
  ('pohoda', 'Pohoda', 'Czech', 'Czech Republic', 'poh-HOH-dah', 'pause', 'state_of_mind', true, 'either', 'any', 'any', 4, 'An unhurried ease where mind, body and surroundings fall into harmony.', 'A relaxed, contented state of being fully at ease — present and unstressed, whether over coffee with friends, a quiet evening in, or a walk with nothing to prove.', ARRAY['Drop the pace and the to-do list for a while', 'Settle into wherever you are — a café, a chair, a path', 'Let things be good enough exactly as they are.']::text[], 'Unclaimed pockets of the day, alone or with easy company.', 'Calm, balanced, gently content.', 'A much-loved Czech word for everyday ease and equilibrium.', NULL, NULL, 17),
  ('friluftsliv', 'Friluftsliv', 'Norwegian', 'Norway', 'FREE-loofts-leev', 'outside', 'doable_activity', true, 'either', 'any', 'any', 5, '"Open-air life" — weaving the outdoors into ordinary days.', 'Not a grand expedition but a way of living that keeps you outside in all weathers, all year, living in tune with nature.', ARRAY['Go outside, whatever the sky is doing', 'Walk, sit, ski, swim or forage — whatever fits the day', 'Stay long enough to stop checking the time.']::text[], 'Year-round, by design.', 'Awake, weathered, more alive than the indoors allows.', 'Lomas groups it under living in harmony with nature; rooted in 19th-century Norwegian Romanticism.', 'Relationships > Pro-sociality > Communality', NULL, 18),
  ('shinrin-yoku', 'Shinrin-yoku', 'Japanese', 'Japan', 'shin-rin-YOH-koo', 'outside', 'doable_activity', true, 'either', 'any', 'any', 5, 'Forest bathing — soaking in the woods through every sense.', 'A slow, aimless immersion among trees: relaxation gained from "bathing" in the forest, figuratively and literally.', ARRAY['Walk into trees and slow right down', 'Notice the light, smell, sound and the air on your skin', 'Let there be no destination.']::text[], 'Any time you can reach trees. Even a small wood will do.', 'Measurably calmer — softer breathing, a quieter mind.', 'Promoted as public health in Japan; supported by research on cortisol and immune markers.', 'Feelings > Positive > Savouring', NULL, 19),
  ('gokotta', 'Gökotta', 'Swedish', 'Sweden', 'yo-KOT-ta', 'outside', 'doable_activity', true, 'either', 'dawn', 'spring', 4, 'Rising at dawn just to go out and hear the first birdsong.', 'Waking early for no reason but to be outside as the birds begin and the world wakes.', ARRAY['Set an early alarm, before the day demands anything', 'Step outside as the light comes up', 'Stand still and just listen.']::text[], 'Early spring and summer mornings.', 'Wonder, and a private head start on the day.', 'Explicitly cited by Lomas as a Swedish savouring word.', 'Feelings > Positive > Savouring', NULL, 20),
  ('uitwaaien', 'Uitwaaien', 'Dutch', 'Netherlands', 'OUT-vai-en', 'outside', 'doable_activity', true, 'either', 'any', 'any', 4, 'To walk into the wind to clear your head.', 'Literally "to wind out" — going into a brisk day to be blown clean of whatever is clouding you, with an emphasis on fresh air and health.', ARRAY['Pick a blustery day instead of avoiding it', 'Walk into the wind — coast, field or hilltop', 'Let it pull the noise out of your head.']::text[], 'Whenever it''s windy and your thoughts feel tangled.', 'Scrubbed clean and clear-headed.', 'Listed by Lomas among savouring words for fresh-air walking.', 'Feelings > Positive > Savouring', NULL, 21),
  ('utepils', 'Utepils', 'Norwegian', 'Norway', 'OO-teh-pilss', 'outside', 'doable_activity', true, 'social', 'afternoon', 'spring', 3, 'The first beer enjoyed outdoors in the sun after winter.', 'A small national celebration of the first cold drink taken outside once the sun returns.', ARRAY['Wait for the first properly warm, bright day', 'Take a cold drink outside — step, bench or park', 'Tip your face to the sun and toast the light coming back.']::text[], 'The first warm days of spring, then all summer.', 'Communal relief that winter is over.', 'Named directly by Lomas as a Norwegian word of revelry.', 'Feelings > Positive > Revelry', NULL, 22),
  ('waldeinsamkeit', 'Waldeinsamkeit', 'German', 'Germany', 'VALD-ine-zam-kite', 'outside', 'doable_activity', true, 'solo', 'any', 'any', 5, 'The soothing solitude of being alone in the woods.', 'A mysterious, slightly sublime feeling of oneness and solitude among trees — the pull of untamed wilderness.', ARRAY['Go alone into woodland', 'Walk slowly or sit still', 'Let the solitude feel spacious rather than lonely.']::text[], 'Solo woodland walks, any season.', 'Meditative calm with a touch of awe.', 'Rooted in German Romanticism; Lomas files it among words for freedom and solitude.', 'Feelings > Complex > Freedom', NULL, 23),
  ('mangata', 'Mångata', 'Swedish', 'Sweden', 'MOHN-gah-ta', 'outside', 'perceptual_noticing', true, 'either', 'night', 'any', 3, 'The shimmering, road-like reflection of the moon on water.', 'A word for the glittering moon-path across the sea — a thing many have seen and never named.', ARRAY['On a clear night near water, find the moon', 'Follow its light down to the surface', 'Watch the path it lays across the water.']::text[], 'Clear nights beside water.', 'Small, quiet awe.', 'Lomas pairs it with the Turkish *gümüşservi* for the same phenomenon.', 'Feelings > Complex > Aesthetics', NULL, 24),
  ('komorebi', 'Komorebi', 'Japanese', 'Japan', 'koh-moh-REH-bee', 'outside', 'perceptual_noticing', true, 'either', 'midday', 'any', 3, 'Sunlight filtering and dappling through leaves.', 'The interplay of light and leaves — a small, fleeting beauty worth pausing for.', ARRAY['Find a tree with sun behind it', 'Watch the light scatter through the leaves', 'Stay with it for a moment before moving on.']::text[], 'Bright days under trees.', 'Gentle delight and present-moment attention.', 'Listed by Lomas among Japanese aesthetic-appreciation words.', 'Feelings > Complex > Aesthetics', NULL, 25),
  ('psithurism', 'Psithurism', 'Greek', 'Greece', 'SITH-yoor-iz-um', 'outside', 'perceptual_noticing', true, 'either', 'any', 'any', 3, 'The sound of wind rustling through trees.', 'A word for one of nature''s quietest pleasures — leaves stirring in the breeze.', ARRAY['Find trees on a breezy day', 'Close your eyes and listen', 'Let the sound be the whole of your attention.']::text[], 'Breezy days near trees.', 'Calm and quietly soothed.', 'Cited by Lomas alongside other words for the sounds and sights of nature.', 'Feelings > Complex > Aesthetics', NULL, 26),
  ('abendrot', 'Abendrot', 'German', 'Germany', 'AH-bent-roht', 'outside', 'perceptual_noticing', true, 'either', 'evening', 'any', 3, 'Stopping to watch the red glow of the setting sun.', 'Literally "evening red" — the warm flush of colour the sky takes as the day ends, long treasured in German Romantic art and music as a moment for quiet wonder.', ARRAY['As the sun lowers, find a window or step outside', 'Watch the colour deepen and shift across the sky', 'Stay until the last of the glow has gone.']::text[], 'Clear evenings, as the sun sets.', 'Calm, a little wistful, glad to have stopped.', 'A favourite of German Romantic poets and painters; set famously to music in Strauss''s "Im Abendrot".', 'Feelings > Complex > Aesthetics', NULL, 27),
  ('ma', 'Ma', 'Japanese', 'Japan', 'mah', 'outside', 'perceptual_noticing', true, 'either', 'any', 'any', 3, 'Noticing the meaningful empty space and silence between things.', 'The pregnant pause, gap or interval — the emptiness that gives shape and meaning to what surrounds it. In Japanese art, music and architecture, the space between is as alive as the things themselves.', ARRAY['Look at a scene and attend to the gaps, not the objects', 'Notice the silence between sounds, the space between words', 'Let the emptiness feel full rather than missing.']::text[], 'A quiet moment anywhere — a room, a piece of music, a conversation.', 'A spacious, settled attention.', 'A foundational idea in Japanese aesthetics, rooted in Zen, where absence carries as much meaning as presence.', 'Feelings > Complex > Aesthetics', NULL, 28),
  ('tystnad', 'Tystnad', 'Swedish', 'Sweden', 'TOOST-nahd', 'outside', 'perceptual_noticing', true, 'solo', 'any', 'any', 4, 'Seeking out deliberate silence and simply listening.', 'Silence treated not as emptiness but as a resource — a deliberate quiet, often found in nature, that lets you hear the world and yourself again.', ARRAY['Find the quietest place you can, ideally outdoors', 'Stop talking, and put the phone away', 'Listen to whatever remains — wind, distance, your own breath.']::text[], 'When the noise of the day has built up and you need to hear yourself think.', 'Clear, settled, attentively calm.', 'Sweden''s wide, quiet landscapes make tystnad a valued part of its culture of nature and stillness.', NULL, NULL, 29),
  ('kaitiakitanga', 'Kaitiakitanga', 'Māori', 'Aotearoa New Zealand', 'KY-tee-ah-kee-TAHNG-ah', 'outside', 'spiritual_practice', true, 'either', 'any', 'any', 4, 'Caring for a piece of the natural world as its guardian.', 'Guardianship and stewardship of land, water and living things, grounded in a reciprocal relationship: the world sustains you, and you are responsible for its wellbeing in return, for those who come after.', ARRAY['Choose a patch of the natural world you can tend — a tree, a stream, a verge, a garden', 'Do one small thing to care for it — clear litter, water it, protect it', 'Return to it, so the care is ongoing rather than one-off.']::text[], 'Whenever you are out in a place worth looking after.', 'Purposeful, connected, part of something larger than yourself.', 'A core value in te ao Māori (the Māori world); kaitiaki are the guardians of a place or treasure. Present it with respect and acknowledgement of its origins.', NULL, 'A living Māori value — frame respectfully and credit its source, not as generic eco-advice.', 30),
  ('fika', 'Fika', 'Swedish', 'Sweden', 'FEE-ka', 'savour', 'social_ritual', true, 'social', 'morning', 'any', 4, 'A coffee-and-cake break, taken seriously, with others.', 'A protected daily pause for a hot drink, something sweet and company — socialising around food and drink.', ARRAY['Step away from work — fika is not done at your desk', 'Make coffee and find something sweet, ideally a cinnamon bun', 'Sit with someone and talk about nothing in particular.']::text[], 'Daily, mid-morning and mid-afternoon. Best shared.', 'Reset, connected, reminded the day isn''t only work.', 'Lomas lists it among words for socialising around food and drink.', 'Feelings > Positive > Revelry', NULL, 31),
  ('sobremesa', 'Sobremesa', 'Spanish', 'Spain and Latin America', 'soh-breh-MEH-sah', 'savour', 'social_ritual', true, 'social', 'afternoon', 'any', 5, 'The lingering talk at the table after the meal is done.', '"Over the table" — unhurried conversation that keeps everyone seated long after the food is gone.', ARRAY['When the plates are cleared, don''t get up', 'Pour another coffee and let the talk wander', 'Let leaving be no one''s priority.']::text[], 'After lunch and dinner, often an hour or more on weekends.', 'Closeness, trust, no rush to part.', 'Named by Lomas as a Spanish word for the pleasure of conversation continuing past the food.', 'Feelings > Positive > Revelry', NULL, 32),
  ('aperitivo', 'Aperitivo', 'Italian', 'Italy', 'ah-peh-ree-TEE-vo', 'savour', 'social_ritual', true, 'social', 'evening', 'any', 4, 'A pre-dinner drink and snack that opens the evening.', 'A gentle ritual marking the seam between the working day and the night.', ARRAY['In the early evening, pour a light drink', 'Set out a few small things to nibble', 'Let it slow you down before dinner, not fill you up.']::text[], 'Early evening, before dinner, usually with others.', 'The day exhales; the evening begins.', 'Sits alongside the wider European culture of unhurried eating and drinking.', NULL, NULL, 33),
  ('merienda', 'Merienda', 'Spanish', 'Spain', 'meh-ree-EN-dah', 'savour', 'social_ritual', true, 'either', 'afternoon', 'any', 3, 'A small, sweet afternoon break to bridge the day.', 'A light afternoon snack — coffee or chocolate with something to eat — carrying you to a late dinner.', ARRAY['Mid-to-late afternoon, pause for a small bite', 'Coffee, hot chocolate, a pastry or some bread', 'Best taken with whoever is near.']::text[], 'Late afternoon, daily.', 'A gentle lift in the long stretch before evening.', 'Common across Spain and much of Latin America.', NULL, NULL, 34),
  ('gongfu-cha', 'Gōngfu chá', 'Chinese', 'China', 'gong-foo CHAH', 'savour', 'doable_activity', true, 'either', 'afternoon', 'any', 5, 'Brewing tea slowly and attentively, as a small meditation.', 'Tea made with care in a tiny pot over many short infusions — the doing of it as restful as the drinking.', ARRAY['Warm a small pot and cup', 'Brew in short, repeated steeps, watching each one', 'Drink slowly and let the ritual hold your attention.']::text[], 'Unhurried afternoons. Alone for calm, or shared for company.', 'Patience, presence, a settled mind.', 'A skilled tea practice with both solitary and social forms.', NULL, NULL, 35),
  ('hara-hachi-bu', 'Hara hachi bu', 'Japanese', 'Okinawa, Japan', 'HA-ra HA-chee boo', 'savour', 'doable_activity', true, 'either', 'any', 'any', 0, 'Eating until you are only eighty percent full.', 'A gentle Okinawan habit of restraint — stopping a little before fullness, on purpose.', ARRAY['Eat slowly enough to notice how you feel', 'Stop when satisfied, not stuffed', 'Leave a little room and let it settle.']::text[], 'At every meal.', 'Light and clear rather than heavy.', 'Linked to Okinawan longevity. Frame as gentle and intuitive, never as restriction.', NULL, 'Avoid presenting as a diet rule; keep the language about comfort, not control.', 36),
  ('borrel', 'Borrel', 'Dutch', 'Netherlands', 'BOH-rel', 'savour', 'social_ritual', true, 'social', 'evening', 'any', 4, 'A casual drinks-and-snacks gathering with friends or colleagues.', 'An informal social drink, often after work, built around easy company.', ARRAY['Gather a few people, somewhere relaxed', 'Put out drinks and simple snacks', 'Keep it loose and unscheduled.']::text[], 'Late afternoon or early evening, social.', 'Light, warm conviviality.', 'Lomas lists *borrel* among words for socialising around food and drink.', 'Feelings > Positive > Revelry', NULL, 37),
  ('kveldsmat', 'Kveldsmat', 'Norwegian', 'Norway', 'KVELS-maht', 'savour', 'social_ritual', true, 'either', 'evening', 'any', 4, 'A simple late-evening bite that quietly closes the day together.', 'A light supper — usually open sandwiches — taken late in the evening. Less about hunger than rhythm: a small, shared marker that the day is winding down.', ARRAY['In the late evening, put out something simple — bread and a few toppings', 'Sit down with whoever is home, or on your own', 'Eat slowly and let the day settle as you do.']::text[], 'Late evening, before bed.', 'Calm, fed, gently rounded-off.', 'An everyday Norwegian rhythm rather than a special occasion — the day''s quiet full stop.', NULL, NULL, 38),
  ('terroir', 'Terroir', 'French', 'France', 'tair-WAHR', 'savour', 'perceptual_noticing', true, 'either', 'any', 'any', 3, 'Tasting the place — soil, weather, hands — in what you eat or drink.', 'The idea that a food or wine carries the character of where it came from: its soil, climate, landscape and the people who made it. To taste with terroir in mind is to taste a place, not just a flavour.', ARRAY['Take something with a clear origin — a cheese, a wine, a fruit, a coffee', 'Taste it slowly and ask what place it speaks of', 'Let the where deepen the what.']::text[], 'Any unhurried meal or drink worth paying attention to.', 'A richer, more grounded kind of pleasure.', 'A French concept from winemaking, now used widely for the way good food expresses its origins.', NULL, NULL, 39),
  ('qahwa', 'Qahwa', 'Arabic', 'Arabian Peninsula', 'KAH-wah', 'savour', 'social_ritual', true, 'social', 'any', 'any', 5, 'Cardamom coffee poured as an act of welcome.', 'The ceremonial Arabic coffee — light, spiced with cardamom, served in small handleless cups — at the heart of hospitality across the Gulf. To offer it is to honour a guest; to receive it is to be made welcome.', ARRAY['Make coffee with care, with cardamom if you have it', 'Serve it to your guests in small cups, eldest first, before yourself', 'Keep the cups topped up as a sign they are welcome to stay.']::text[], 'Whenever someone visits, or any gathering you want to open warmly.', 'Generous, hospitable, unhurried.', 'Arabic coffee culture is recognised by UNESCO as intangible cultural heritage and is a deep-rooted symbol of welcome and generosity.', NULL, NULL, 40),
  ('abbiocco', 'Abbiocco', 'Italian', 'Italy', 'ahb-bee-OHK-koh', 'savour', 'perceptual_noticing', true, 'either', 'afternoon', 'any', 4, 'The happy drowsiness after a good meal — and letting yourself have it.', 'That pleasant heaviness that comes over you after a full, satisfying meal. Rather than fighting it, the word treats it as a small pleasure to be honoured with a pause.', ARRAY['After a good meal, notice the drowsiness arriving', 'Don''t fight it with caffeine or a task', 'Let yourself sink into a few slow minutes, or a short doze.']::text[], 'After lunch, especially a big or rich one.', 'Warm, sated, pleasantly heavy.', 'An affectionate Italian word for post-meal sleepiness, treated as a comfort rather than a failing.', NULL, NULL, 41),
  ('tarab', 'Tarab', 'Arabic', 'Middle East and North Africa', 'TAH-rab', 'savour', 'perceptual_noticing', true, 'either', 'any', 'any', 5, 'Being so moved by music that you lose yourself in it.', 'A state of ecstasy and deep emotional transport brought on by music — the merging of listener and song until the boundary between them softens. More than enjoyment; a kind of rapture.', ARRAY['Choose music that moves you, and remove distractions', 'Close your eyes and give it your whole attention', 'Let it carry you rather than keeping it as background.']::text[], 'Any time you can listen to music properly, alone or among others who feel it too.', 'Swept up, stirred, gloriously absorbed.', 'A central idea in Arabic musical tradition, where performer and audience reach this heightened state together.', NULL, NULL, 42),
  ('gezelligheid', 'Gezelligheid', 'Dutch', 'Netherlands', 'heh-ZELL-ick-hyte', 'gather', 'social_ritual', true, 'social', 'evening', 'any', 4, 'Cosy togetherness — the warmth of good company.', 'A shared, convivial warmth that comes from being among people you like; considered the heart of Dutch social life.', ARRAY['Bring a few people into a warm, easy space', 'Keep it informal — drinks, snacks, no agenda', 'Let conversation and staying-late do the rest.']::text[], 'Meals, evenings, café terraces. Almost always with others.', 'Belonging, ease, the glow of good company.', 'From *gezel*, "companion". A social cousin of the cosiness words.', 'Feelings > Positive > Cosiness', NULL, 43),
  ('parea', 'Parea', 'Greek', 'Greece', 'pah-REH-ah', 'gather', 'social_ritual', true, 'social', 'evening', 'any', 4, 'Your close companionship group, and the joy of simply being together.', 'A circle of friends gathered to share food, drink, talk and time, with no purpose beyond the company itself.', ARRAY['Gather your regular few', 'Share a long table, food and drink', 'Let the evening run with no end-time.']::text[], 'Evenings and long meals, social.', 'Deep belonging and unhurried friendship.', 'Named by Lomas among words for socialising around food and drink.', 'Feelings > Positive > Revelry', NULL, 44),
  ('craic', 'Craic', 'Irish', 'Ireland', 'crack', 'gather', 'social_ritual', true, 'social', 'evening', 'any', 4, 'Lively talk, laughter and good times together.', 'The whole warm bundle of fun, banter and camaraderie that makes a gathering worth being at.', ARRAY['Get a few people together, ideally somewhere lively', 'Trade stories and laugh', 'Stay for the conversation, not the schedule.']::text[], 'Pubs, kitchens, anywhere people gather.', 'Lifted, connected, sides aching from laughing.', '"What''s the craic?" is everyday Irish usage.', NULL, NULL, 45),
  ('passeggiata', 'Passeggiata', 'Italian', 'Italy', 'pah-seh-JAH-tah', 'gather', 'social_ritual', true, 'social', 'evening', 'any', 4, 'A leisurely evening stroll to see and greet your neighbours.', 'The slow communal walk through town in the evening — to move a little and to be among everyone else doing the same.', ARRAY['In the early evening, go out for a slow walk', 'Take the main streets or the square, no destination', 'Nod, stop and chat; the point is the people.']::text[], 'Evenings, especially weekends.', 'Part of something — a town breathing together.', 'Akin to the Greek *volta* and French *flâner*, both noted by Lomas for strolling without a destination.', 'Feelings > Positive > Savouring', NULL, 46),
  ('volta', 'Volta', 'Greek', 'Greece', 'VOL-tah', 'gather', 'social_ritual', true, 'either', 'evening', 'any', 4, 'A relaxed evening stroll, taking in the sights and the people.', 'A leisurely walk with no destination, valued for the sense of freedom and the chance to greet passers-by.', ARRAY['Head out in the cool of the evening', 'Wander the front, the square or the streets', 'Let yourself be unhurried and sociable.']::text[], 'Evenings, social or solo.', 'Freedom, ease and gentle connection.', 'Lomas names *volta* and *flâner* together as strolling words carrying a sense of possibility.', 'Feelings > Positive > Savouring', NULL, 47),
  ('renao', 'Rènao', 'Chinese', 'China', 'ruh-NOW', 'gather', 'social_ritual', true, 'social', 'evening', 'any', 4, 'The warm, buzzing liveliness of a happy crowd.', '"Hot and noisy", and entirely a good thing — the vital hum of people, food and festivity together.', ARRAY['Head toward where people gather — a market, a feast, a festival', 'Let yourself be carried by the noise and bustle', 'Eat, talk, share the crowd''s energy.']::text[], 'Meals, festivals, especially Lunar New Year.', 'Alive, included, lifted by the crowd.', 'A positively valued quality of social atmosphere in China.', NULL, NULL, 48),
  ('hooponopono', 'Hoʻoponopono', 'Hawaiian', 'Hawaiʻi', 'HO-oh-pono-pono', 'gather', 'relational_practice', true, 'either', 'any', 'any', 4, 'A gentle ritual of forgiveness — "to make right".', 'A practice of releasing resentment and repairing a bond, which can be done quietly, even with yourself.', ARRAY['Bring to mind the person or hurt you are holding', 'Slowly repeat: I''m sorry. Please forgive me. Thank you. I love you.', 'Let the words loosen what you have been carrying.']::text[], 'Whenever resentment has settled and needs releasing.', 'Lighter, softer, more at peace.', 'A sacred Hawaiian reconciliation practice. Present with respect and acknowledgement of its origins.', NULL, 'Sacred living tradition — frame respectfully, not as a generic self-help hack.', 49),
  ('cwtch', 'Cwtch', 'Welsh', 'Wales', 'kutch', 'gather', 'relational_practice', true, 'social', 'any', 'any', 0, 'A hug that wraps you in safety — also a safe little space.', 'More than an embrace: a hold that says you are safe here. The word doubles as a cosy nook.', ARRAY['Find someone you love', 'Hold them like you mean it, without rushing', 'Or make a cwtch of a space — a snug corner that feels like shelter.']::text[], 'Any time warmth or comfort is needed.', 'Held, safe, quietly reassured.', 'Cited by Lomas under cosiness and safety; means both "to hug" and "a safe, welcoming place".', 'Feelings > Positive > Cosiness', NULL, 50),
  ('retrouvailles', 'Retrouvailles', 'French', 'France', 'ruh-troo-VYE', 'gather', 'relational_practice', true, 'social', 'any', 'any', 0, 'The joy of reuniting with someone after a long time apart.', 'Literally "rediscoveries" — the happiness of being together again after separation.', ARRAY['Reach out to someone you have not seen in too long', 'Make the plan to actually meet', 'Let the reunion be the whole point.']::text[], 'Any reunion worth marking.', 'Warm, full-hearted reconnection.', 'Listed by Lomas among words for affection and desire.', 'Relationships > Intimacy > Desire', NULL, 51),
  ('talkoot', 'Talkoot', 'Finnish', 'Finland', 'TAL-koht', 'gather', 'social_ritual', true, 'social', 'any', 'any', 0, 'Coming together to do a shared task for the common good.', 'Voluntary collective work — neighbours or a community pitching in together on something that benefits everyone.', ARRAY['Find a task that helps the group — a tidy-up, a build, a harvest', 'Invite people to do it together', 'Share the work and the company.']::text[], 'Whenever a shared job needs doing.', 'Belonging and the satisfaction of shared effort.', 'Lomas groups it with the Norwegian *dugnad* and Swedish *talko* as words for collective tasks.', 'Relationships > Pro-sociality > Communality', NULL, 52),
  ('nunchi', 'Nunchi', 'Korean', 'Korea', 'NOON-chee', 'gather', 'relational_practice', false, 'social', 'any', 'any', 0, 'The art of reading a room and responding with care.', 'Literally "eye-measure" — sensing the mood and unspoken cues of others to keep social harmony.', ARRAY['Before speaking, take in the room''s mood', 'Notice what is unsaid as much as what is said', 'Respond in a way that keeps everyone at ease.']::text[], 'Any social situation.', 'Smoother relationships and social ease.', 'Named by Lomas as a Korean non-verbal communication skill. Better as a learnable skill than a timed prompt.', 'Relationships > Pro-sociality > Communication', NULL, 53),
  ('mehfil', 'Mehfil', 'Urdu and Persian', 'South Asia', 'MEH-fil', 'gather', 'social_ritual', true, 'social', 'evening', 'any', 5, 'An evening gathering for poetry, music and good talk.', 'An intimate company assembled for the pleasure of shared culture — verses recited, songs sung, conversation savoured late into the night.', ARRAY['Gather a few people who enjoy words or music', 'Share something — a poem, a song, a story — and invite others to add theirs', 'Let the evening unfold slowly, with food and drink to hand.']::text[], 'Evenings, when there is time to linger.', 'Cultured warmth and unhurried connection.', 'A cherished tradition in South Asian and Persian culture, historically the setting for poetry and classical music.', NULL, NULL, 54),
  ('pagmamano', 'Pagmamano', 'Filipino', 'Philippines', 'pahg-mah-MAH-noh', 'gather', 'relational_practice', true, 'social', 'any', 'any', 0, 'Pressing an elder''s hand to your forehead to ask their blessing.', 'A gesture of respect in which a younger person gently takes an elder''s hand and touches it to their forehead, saying "mano po", seeking and receiving a blessing. It honours the bond between generations.', ARRAY['On greeting an elder, take their right hand gently', 'Bow slightly and touch the back of their hand to your forehead', 'Receive their words of blessing in return.']::text[], 'Greeting elders — arriving, leaving, or at family gatherings.', 'Respect, belonging, the warmth of being blessed.', 'A pre-colonial Filipino gesture still practised daily; present it as a living mark of respect for elders.', NULL, 'A living tradition of respect — present it with care, not as a novelty.', 55),
  ('talanoa', 'Talanoa', 'Samoan, Fijian and Tongan', 'Pacific Islands', 'tah-lah-NOH-ah', 'gather', 'social_ritual', true, 'social', 'any', 'any', 5, 'Open, unhurried, circular storytelling that builds understanding.', 'A Pacific way of talking together in which people share stories and feelings openly, without a fixed agenda, until understanding and consensus grow between them.', ARRAY['Sit together with no rush and no fixed outcome', 'Let each person share their story; listen without interrupting', 'Let understanding build between you rather than steering to a conclusion.']::text[], 'When something needs talking through, or simply to deepen a connection.', 'Heard, connected, gently understood.', 'A valued practice across Samoa, Fiji and Tonga, now used widely in Pacific community and research life. Present it with respect for its origins.', NULL, 'A living Pacific practice — frame respectfully and credit its source.', 56),
  ('seva', 'Seva', 'Sanskrit', 'India and Sikh communities', 'SEH-vah', 'gather', 'relational_practice', true, 'either', 'any', 'any', 4, 'A small act of selfless service, expecting nothing back.', 'Service offered freely for the good of others, as a path of the heart rather than a transaction. Central to Sikh and Hindu life — from serving food to quiet, unseen help.', ARRAY['Find one thing you can do to ease someone''s day', 'Do it freely, without being asked and without expecting thanks', 'Let the giving be the whole of the reward.']::text[], 'A daily orientation toward others; any chance to help.', 'Useful, connected, quietly fulfilled.', 'A sacred concept in Sikh and Hindu traditions — embodied in practices like the langar, the free community kitchen. Present it with respect for that depth.', 'Relationships > Pro-sociality > Kindness', 'A sacred living practice in Sikh and Hindu traditions — frame respectfully.', 57),
  ('yuimaru', 'Yuimaru', 'Okinawan', 'Okinawa, Japan', 'yoo-ee-MAH-roo', 'gather', 'social_ritual', true, 'social', 'any', 'any', 0, 'A circle of neighbours who quietly help one another.', 'The Okinawan spirit of mutual aid — a cooperative circle where people pool effort and care, helping wherever it is needed, woven through daily life rather than called on only in crisis.', ARRAY['Think of your circle of neighbours, friends or family', 'Offer help where it''s needed, or accept it when offered', 'Keep the giving and receiving flowing both ways over time.']::text[], 'Ongoing, as part of how a community looks after itself.', 'Held, mutual, part of a circle.', 'Linked to Okinawa''s famed longevity and its lifelong *moai* support groups.', 'Relationships > Pro-sociality > Communality', NULL, 58),
  ('gotong-royong', 'Gotong Royong', 'Indonesian and Malay', 'Indonesia', 'GOH-tong ROY-ong', 'gather', 'social_ritual', true, 'social', 'any', 'any', 0, 'Everyone pitching in together on a shared task.', 'Communal work for the common good — neighbours coming together to lighten a job by sharing it, from cleaning a street to preparing for a celebration, in a spirit of reciprocity and togetherness.', ARRAY['Find a task that helps the whole group', 'Invite people to do it together rather than alone', 'Share the work, the food and the company as you go.']::text[], 'Whenever a shared job needs doing.', 'Belonging, lightness, the satisfaction of shared effort.', 'A cornerstone of Indonesian social life and national identity.', 'Relationships > Pro-sociality > Communality', NULL, 59),
  ('meraki', 'Meraki', 'Greek', 'Greece', 'meh-RAH-kee', 'gather', 'doable_activity', true, 'either', 'any', 'any', 5, 'Doing something — cooking, making — with all your soul.', 'To pour yourself, your love and your creativity into what you do, so that a piece of you ends up in the result. Often used of cooking, hosting and craft.', ARRAY['Choose something you''re making for others — a meal, a gift, a space', 'Slow down and put real care into it', 'Let the love you bring be part of what you give.']::text[], 'Any time you make something for others.', 'Absorbed, generous, proud in a quiet way.', 'A Greek word for leaving a little of your soul in your work, especially when you do it for others.', NULL, NULL, 60),
  ('xenia', 'Xenia', 'Greek', 'Greece', 'kse-NEE-ah', 'gather', 'relational_practice', true, 'social', 'any', 'any', 4, 'Treating a guest, even a stranger, with sacred generosity.', 'The ancient Greek code of hospitality — the warm, almost sacred duty to welcome a guest or stranger, offer them comfort, and ask nothing in return.', ARRAY['When someone arrives, make them feel genuinely welcome', 'Offer the best of what you have — a seat, food, drink, your attention', 'Let them feel they are a guest, not an intrusion.']::text[], 'Whenever someone comes to your door, expected or not.', 'Open-hearted, generous, gracious.', 'A revered value in ancient Greece, considered watched over by the gods; still echoed in Greek hospitality today.', 'Relationships > Pro-sociality > Hospitality', NULL, 61),
  ('zyczliwosc', 'Życzliwość', 'Polish', 'Poland', 'zhich-LEE-voshch', 'gather', 'relational_practice', true, 'either', 'any', 'any', 0, 'Choosing active, everyday kindness toward others.', 'A warm goodwill and benevolence expressed in action — wishing others well and showing it, treating people *po ludzku*, "humanely", even amid life''s difficulties.', ARRAY['Pick one person you''ll cross paths with today', 'Offer them a small, genuine kindness — a word, a hand, patience', 'Expect nothing back; let the goodwill be the point.']::text[], 'Any ordinary encounter, all through the day.', 'Warm, generous, humanly connected.', 'A valued Polish disposition of active kindness and goodwill toward others.', 'Relationships > Pro-sociality > Kindness', NULL, 62),
  ('manaakitanga', 'Manaakitanga', 'Māori', 'Aotearoa New Zealand', 'mah-NAH-kee-TAHNG-ah', 'gather', 'relational_practice', true, 'social', 'any', 'any', 4, 'Welcoming and caring for others so generously that their mana is lifted.', 'Hospitality, kindness and care extended to others — nurturing guests and community with such warmth and generosity that their standing and wellbeing are raised. To give manaaki is to honour both guest and host.', ARRAY['When you host or help someone, give it your full care', 'Offer food, comfort and genuine attention, generously', 'Make the other person feel valued and uplifted, not merely accommodated.']::text[], 'Hosting, helping, or welcoming anyone into your space.', 'Generous, warm, dignified connection.', 'A central value in te ao Māori; the care you show others reflects and builds the mana of all. Present it with respect for its origins.', 'Relationships > Pro-sociality > Hospitality', 'A living Māori value — frame respectfully and credit its source.', 63),
  ('ikigai', 'Ikigai', 'Japanese', 'Japan', 'EE-kee-guy', 'reflect', 'state_of_mind', false, 'solo', 'any', 'any', 0, 'A reason to get up in the morning, found in small daily joys.', 'In its true Japanese sense, the feeling that life is good and worthwhile — drawn from ordinary things, not a grand single purpose.', ARRAY['Ask what, however small, you look forward to', 'Notice what absorbs you and leaves you content', 'Make a little more room for it tomorrow.']::text[], 'A quiet reflection, returned to often.', 'Quiet purpose drawn from ordinary days.', 'Lomas defines it as a "reason for being". The popular four-circle Venn diagram is a Western invention (2014), not traditional Japanese usage.', 'Character > Resources > Flourishing', 'Do not reproduce the Western Venn-diagram version as if authentic.', 64),
  ('lagom', 'Lagom', 'Swedish', 'Sweden', 'LAH-gom', 'reflect', 'state_of_mind', false, 'either', 'any', 'any', 0, 'Not too much, not too little — just right.', 'A philosophy of balance and moderation: doing anything to just the right degree.', ARRAY['Look at one part of life that feels like too much, or too little', 'Ask what "just enough" would be', 'Adjust gently toward it and stop there.']::text[], 'Whenever life tips toward excess or scarcity.', 'Steady, sustainable contentment.', 'Lomas lists it among character words, as a valued sense of moderation.', 'Character > Resources > Decency', NULL, 65),
  ('wabi-sabi', 'Wabi-sabi', 'Japanese', 'Japan', 'WAH-bee SAH-bee', 'reflect', 'perceptual_noticing', false, 'either', 'any', 'any', 0, 'Finding beauty in imperfection and impermanence.', '*Wabi* (imperfect beauty) and *sabi* (aged beauty) together — a "dark, desolate sublimity" that values the worn and the irregular.', ARRAY['Pick up something old or imperfect you own', 'Look at the wear, cracks and irregularities', 'Let them be the beauty, not the flaw.']::text[], 'Any moment you catch yourself wanting things flawless.', 'Acceptance and a softer eye for the world.', 'Drawn directly from Lomas''s discussion of Japanese aesthetics.', 'Feelings > Complex > Aesthetics', NULL, 66),
  ('mono-no-aware', 'Mono no aware', 'Japanese', 'Japan', 'MOH-no no ah-WAH-reh', 'reflect', 'perceptual_noticing', false, 'either', 'any', 'spring', 0, 'The gentle sadness of knowing beautiful things pass.', 'The pathos of understanding that the world and its beauty are transient — a bittersweet awareness that deepens appreciation.', ARRAY['Notice something lovely and temporary — blossom, light, a mood', 'Let yourself feel that it won''t last', 'Let the brevity enrich the beauty rather than spoil it.']::text[], 'Cherry blossom, sunsets, last days.', 'Tender presence and a richer sense of now.', 'Lomas describes the related *aware* as the bittersweetness of a brief, fading moment of beauty.', 'Feelings > Complex > Aesthetics', NULL, 67),
  ('sisu', 'Sisu', 'Finnish', 'Finland', 'SEE-soo', 'reflect', 'state_of_mind', false, 'solo', 'any', 'any', 0, 'Quiet, stubborn courage in the face of hardship.', 'Extraordinary determination and resolve that shows up after your strength was supposed to run out.', ARRAY['Name the hard thing plainly', 'Take the next small step, not the whole mountain', 'Keep going past the point you would normally stop.']::text[], 'When something is hard and quitting is tempting.', 'Grounded resolve and quiet pride.', 'Lomas characterises sisu as extraordinary determination in the face of adversity; the talk that inspired his paper was about sisu.', 'Character > Resources > Grit', NULL, 68),
  ('ubuntu', 'Ubuntu', 'Nguni Bantu', 'Southern Africa', 'uu-BUUN-tuu', 'reflect', 'relational_practice', false, 'social', 'any', 'any', 0, '"I am because we are" — humanity through one another.', 'Being kind to others on account of a shared humanity; my wellbeing is bound up in yours.', ARRAY['Think of someone whose day you could ease', 'Do one small, generous thing, expecting nothing', 'Notice how your wellbeing is tangled with theirs.']::text[], 'A daily orientation toward others.', 'Connected, useful, part of something larger.', 'Lomas quotes Desmond Tutu: my humanity is caught up in yours. A serious ethical concept; treat with depth.', 'Relationships > Pro-sociality > Kindness', NULL, 69),
  ('saudade', 'Saudade', 'Portuguese', 'Portugal and Brazil', 'sow-DAHD', 'reflect', 'state_of_mind', false, 'solo', 'any', 'any', 0, 'A bittersweet longing for someone or something absent.', 'A melancholic, dreaming nostalgia for a person, place or time far away in space or time — even for things that may not exist.', ARRAY['Let the missing-feeling come instead of pushing it away', 'Hold the memory gently; let it be sweet as well as sad', 'Maybe write it down, or play the song that holds it.']::text[], 'When something loved feels far away.', 'A soft, full-hearted ache that honours what mattered.', 'Lomas treats it as a key Portuguese emotion; central to fado music. An ambivalent feeling, not a pick-me-up.', 'Feelings > Complex > Longing', 'Melancholic by nature — offer as gentle reflection, never as a mood-fix prompt.', 70),
  ('natsukashii', 'Natsukashii', 'Japanese', 'Japan', 'nat-soo-KAH-shee', 'reflect', 'state_of_mind', false, 'either', 'any', 'any', 0, 'Fond nostalgia for the past — happy for the memory, sad it is gone.', 'A warm, longing pull toward a fond memory, tinged with the sadness that it is no longer.', ARRAY['Let an old memory surface — a song, a smell, a photo', 'Sit with the warmth of it', 'Let the sweetness and the ache coexist.']::text[], 'When something stirs a fond memory.', 'Warm, wistful tenderness.', 'Listed by Lomas among words for longing and nostalgia.', 'Feelings > Complex > Longing', NULL, 71),
  ('sukha', 'Sukha', 'Sanskrit', 'India', 'SOO-kah', 'reflect', 'state_of_mind', false, 'solo', 'any', 'any', 0, 'Genuine, lasting happiness rooted in inner maturity.', 'In Buddhism, a stable flourishing that does not depend on circumstance, in contrast to fleeting hedonic pleasure.', ARRAY['Notice the difference between a passing high and a steady contentment', 'Tend the steady kind — through calm, ethics, attention', 'Let it be unhurried; it is cultivated, not chased.']::text[], 'A long-term orientation rather than a single act.', 'Deep, durable wellbeing.', 'Lomas contrasts sukha with the more fleeting *ananda* and *khushii*. A spiritual concept; use as a reflective theme.', 'Feelings > Positive > Joy/bliss', NULL, 72),
  ('eudaimonia', 'Eudaimonia', 'Greek', 'Greece', 'yoo-day-MOH-nee-ah', 'reflect', 'state_of_mind', false, 'solo', 'any', 'any', 0, 'Flourishing through living well and fully.', 'A sense of fulfilment and flourishing; in its original sense, being infused with grace, and in modern psychology, a life of meaning and growth.', ARRAY['Ask what living well means to you, beyond feeling good', 'Choose one action that serves it', 'Let meaning, not just pleasure, guide the choice.']::text[], 'A guiding orientation.', 'Deep fulfilment.', 'A foundational concept in positive psychology, noted by Lomas.', 'Feelings > Positive > Joy/bliss', NULL, 73),
  ('joie-de-vivre', 'Joie de vivre', 'French', 'France', 'zhwah duh VEE-vruh', 'reflect', 'state_of_mind', false, 'either', 'any', 'any', 0, 'An exuberant zest for life.', 'The knack of knowing how to live — a sustained, boundless enjoyment of the here and now.', ARRAY['Find the small pleasure available right now', 'Lean into it fully rather than half-noticing', 'Let enjoyment be a habit, not an occasion.']::text[], 'A way of meeting daily life.', 'Lightness and generalised joy.', 'Lomas describes it as joy generalised, a philosophy of life.', 'Character > Resources > Flourishing', NULL, 74),
  ('kaizen', 'Kaizen', 'Japanese', 'Japan', 'KY-zen', 'reflect', 'doable_activity', true, 'solo', 'any', 'any', 0, 'Getting better by the smallest possible step.', 'Continuous, tiny improvement — change so small it is almost easy, repeated until it adds up.', ARRAY['Choose one thing you would like to improve', 'Make the next step almost laughably small', 'Repeat it tomorrow and let it compound.']::text[], 'Any goal that feels too big to start.', 'Progress without pressure.', 'Maps cleanly onto habit-building; one of the few reflective-cluster terms that is directly promptable.', NULL, NULL, 75),
  ('dadirri', 'Dadirri', 'Ngangikurungkurr', 'Aboriginal Australia', 'dah-DEER-ree', 'reflect', 'spiritual_practice', false, 'solo', 'any', 'any', 0, 'Deep, still, reflective and respectful listening.', 'A contemplative inner stillness and quiet awareness — a deep listening to country, to others and to oneself.', ARRAY['Find quiet and stillness', 'Listen, without needing to respond or fix', 'Let the silence and attention be enough.']::text[], 'A contemplative practice rather than a quick activity.', 'Stillness, connection and renewal.', 'A sacred Aboriginal Australian practice associated with Miriam-Rose Ungunmerr. Treat with deep respect and acknowledge its source.', 'Relationships > Pro-sociality > Communication', 'Sacred Indigenous practice — represent carefully and never trivialise.', 76),
  ('shibui', 'Shibui', 'Japanese', 'Japan', 'shih-BOO-ee', 'reflect', 'perceptual_noticing', true, 'either', 'any', 'any', 3, 'Quiet, understated beauty that deepens the longer you look.', 'A subtle, unshowy elegance — beauty that is restrained and simple on the surface but reveals more depth and refinement the more time you give it.', ARRAY['Find something plain but well-made — an object, a room, a piece of music', 'Resist the wish for it to be flashier', 'Look longer, and notice the richness in its restraint.']::text[], 'Any moment you catch yourself craving the loud or the new.', 'A calm, matured appreciation.', 'A Japanese aesthetic ideal prizing understatement and quiet depth over obvious display.', 'Feelings > Complex > Aesthetics', NULL, 77),
  ('darshan', 'Darshan', 'Sanskrit', 'India and Nepal', 'DAR-shan', 'reflect', 'spiritual_practice', true, 'either', 'any', 'any', 3, 'The sacred act of beholding, and being beheld by, the divine.', 'An auspicious seeing — to look upon a deity, holy person or sacred image and to be seen in return; a two-way exchange of grace, not merely a glance.', ARRAY['Bring your attention to something you hold sacred', 'Behold it fully and unhurriedly, and let yourself be seen in turn', 'Receive the moment as a gift rather than grasping at it.']::text[], 'At a shrine, in prayer, or any moment of reverence.', 'Reverent, blessed, connected to something greater.', 'A core practice in Hindu worship, also found in Jain and Buddhist traditions. Present it with respect for its sacred meaning.', NULL, 'A sacred religious practice — frame respectfully, not as a generic mindfulness exercise.', 78),
  ('sabr', 'Sabr', 'Arabic', 'Middle East', 'SAB-r', 'reflect', 'state_of_mind', false, 'solo', 'any', 'any', 0, 'Dignified, active patience that endures hardship without complaint.', 'Not passive resignation but a steadfast, courageous patience — holding firm and trusting through difficulty, keeping one''s composure and dignity when things are hard.', ARRAY['Name the hard thing you are facing plainly', 'Choose to meet it with steadiness rather than struggle against it', 'Hold on, and let patience itself become a kind of strength.']::text[], 'When something is hard and cannot be rushed or fixed.', 'Grounded, composed, quietly resilient.', 'A central virtue in Islam, described as "half of faith". Present it with respect for that source. A reflective theme rather than a quick prompt.', 'Character > Resources > Grit', 'An Islamic virtue with deep religious meaning — frame respectfully.', 79),
  ('sumaq-kawsay', 'Sumaq Kawsay', 'Quechua', 'Andes (Ecuador, Peru, Bolivia)', 'SOO-mahk KOW-sigh', 'reflect', 'spiritual_practice', false, 'social', 'any', 'any', 0, 'Living well in balance with community and the living world.', 'Often translated "good living" or *buen vivir* — a vision of the good life as harmony and reciprocity between people, community and nature, rather than individual accumulation.', ARRAY['Ask where your life could be more in balance with others and the land', 'Choose enough over more, and reciprocity over taking', 'Let wellbeing be something shared, not hoarded.']::text[], 'A guiding orientation, returned to often.', 'Connected, balanced, part of a living whole.', 'An Indigenous Andean philosophy, written into the constitutions of Ecuador and Bolivia. Treat it as a living Indigenous worldview, not abstract "ancient wisdom".', NULL, 'A living Indigenous philosophy — represent with respect and acknowledge its source.', 80),
  ('hiraeth', 'Hiraeth', 'Welsh', 'Wales', 'HEER-ireth', 'reflect', 'state_of_mind', false, 'solo', 'any', 'any', 0, 'A deep longing for a home or time you can''t return to.', 'A bittersweet yearning for a place, a time or a way of life now gone — even a homesickness for somewhere that may never quite have existed.', ARRAY['Let the longing come instead of pushing it away', 'Hold the memory of what you miss gently, sweetness and ache together', 'Let it remind you of what mattered.']::text[], 'When something stirs a yearning for a lost home or time.', 'A soft, full-hearted ache that honours what was loved.', 'A defining word in Welsh culture, close kin to the Portuguese *saudade*. An ambivalent feeling, not a pick-me-up.', 'Feelings > Complex > Longing', 'Melancholic by nature — offer as gentle reflection, never as a mood-fix.', 81),
  ('tizita', 'Tizita', 'Amharic', 'Ethiopia', 'tih-ZEE-tah', 'reflect', 'state_of_mind', false, 'either', 'any', 'any', 0, 'Bittersweet remembering — the Ethiopian blues of longing and love.', 'A tender nostalgia and longing for the past, both ache and comfort — so central to Ethiopian feeling that it names a whole musical mode built to express it.', ARRAY['Let an old memory rise — through a song, a face, a place', 'Sit with its warmth and its sadness together', 'Let the missing be a way of honouring what you loved.']::text[], 'When something stirs a fond, aching memory.', 'Warm, wistful, sweetly sorrowful.', 'At the heart of Ethiopian music and feeling, akin to *saudade* and the blues.', 'Feelings > Complex > Longing', 'Melancholic by nature — offer as gentle reflection, not a mood-fix.', 82),
  ('duende', 'Duende', 'Spanish', 'Spain (Andalusia)', 'DWEN-deh', 'reflect', 'state_of_mind', false, 'either', 'any', 'any', 0, 'The shiver of raw soul and authenticity in art or a moment.', 'A mysterious power of deep emotion and authenticity — the spine-tingling force that rises in flamenco, music or art when something true and soulful breaks through. To "have duende" is to move others from the depths.', ARRAY['Seek out art or music that comes from somewhere real', 'Let it reach you instead of holding it at arm''s length', 'Notice the shiver when raw truth breaks through.']::text[], 'In the presence of art, music or a moment of real depth.', 'Moved to the core; hair-raising authenticity.', 'Famously explored by the poet Federico García Lorca as the soul of flamenco and Spanish art.', 'Feelings > Complex > Aesthetics', NULL, 83),
  ('gonul', 'Gönül', 'Turkish', 'Türkiye', 'gö-NULL', 'reflect', 'state_of_mind', false, 'solo', 'any', 'any', 0, 'The inner heart-home where love and longing live.', 'Somewhere between "heart" and "soul" — the seat of one''s deepest feelings, desires and affections. Not the body''s heart but the inner home of love, will and yearning.', ARRAY['Turn your attention inward to what your gönül truly wants', 'Notice where your affection and longing genuinely pull you', 'Let that inner voice be heard, beneath the day''s noise.']::text[], 'A reflective check-in with your deeper feelings.', 'Tender, honest, inwardly attuned.', 'A poetic Turkish word, rich in Sufi tradition, for the inner seat of feeling and love.', NULL, NULL, 84),
  ('mamihlapinatapai', 'Mamihlapinatapai', 'Yaghan', 'Tierra del Fuego', 'mah-mee-lah-pin-ah-TAH-pie', 'reflect', 'relational_practice', false, 'social', 'any', 'any', 0, 'The wordless shared look, each hoping the other will begin.', 'That charged, silent glance between two people who both want the same thing but each waits for the other to begin — a whole unspoken understanding held in a single look.', ARRAY['Notice the moment a glance carries more than words could', 'Let the shared understanding be enough for a beat', 'If it matters, be the one who gently begins.']::text[], 'Those wordless moments of mutual, unspoken wanting.', 'Tender, suspended, quietly understood.', 'From Yaghan, an Indigenous language of Tierra del Fuego now critically endangered; often called one of the world''s most succinct words. Credit its source with care.', 'Relationships > Intimacy > Desire', 'From a critically endangered Indigenous language — credit its origin and handle with respect.', 85),
  ('orenda', 'Orenda', 'Wyandot (Huron)', 'Northeast North America', 'oh-REN-dah', 'reflect', 'spiritual_practice', false, 'solo', 'any', 'any', 0, 'The inner power of will to shape the world against fate.', 'A spiritual force or energy held to dwell in people and things — the invocable power of will by which a person can affect their own life and the world, even against the pull of circumstance.', ARRAY['Name the part of your situation you can still influence', 'Bring your will and intention to bear on that, not on what you can''t change', 'Act from your own strength rather than waiting on fate.']::text[], 'When circumstances feel fixed but you still have a choice in how you meet them.', 'Empowered, willful, quietly defiant of fate.', 'A concept attributed to the Wyandot (Huron) and wider Iroquoian peoples, recorded by early ethnographers; represent it with respect and awareness that such records are imperfect.', 'Character > Resources > Grit', 'An Indigenous spiritual concept known largely through older outside accounts — frame respectfully and tentatively.', 86)
